var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"윽...... 크으......","JPN":"うっ……くっ……","ENG":"Ugh... Gah...","TWN":"呃……唔……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"항상 당신에게는 맛있는 냄새가 났어요, 리벳.","JPN":"いつもあなたからは美味しそうな匂いがしていたんですよ、リベット。","ENG":"We've always felt that you smelled delicious, Rivet.","TWN":"妳身上一直有很美味的味道，里維。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"당신의 오랜 용병 생활로 쌓은 지식이라면...... 분명 제 허기를 달래주겠지요?","JPN":"あなたの長い傭兵生活で積み重ねた知識ならば……きっと我々の飢えも満たされますよね？","ENG":"The amount of knowledge you've accumulated while working as a mercenary will be more than enough to fill our stomach.","TWN":"如果是妳長年的傭兵生活所累積的知識……一定能滿足我的飢餓感吧？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그...... 그만둬요, 에델!","JPN":"や……やめてください、エデル！","ENG":"S- stop it, Edel!","TWN":"住……住手，艾瑟兒！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"네? 레지나 님, 어째서요?","JPN":"え？　レジーナ様、なぜです？","ENG":"I'm sorry? Why should I, Miss Regina?","TWN":"咦？蕾佳娜大人，怎麼了嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어째서라뇨! 그, 리벳은 당신이 고용한 동료잖아요!","JPN":"なぜですって！？　だって、リベットはあなたが雇った仲間でしょう！","ENG":"What do you mean, why? Rivet is a colleague that you hired yourself!","TWN":"什麼怎麼了！那個，里維不是妳雇傭的夥伴嗎！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"저도 아쉬워요. 하지만 아이들이 이렇게 보채고 있는 걸요?","JPN":"我々も残念です。ですが、この子たちがこんなに食べたがっているので……","ENG":"It's not like I don't feel sorry, but the babies are crying from hunger.","TWN":"我也很遺憾，但是孩子們正纏著我呢？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그게 무슨 상관이에요! 배가 고프다고 동료를 잡아 먹으면 어떻게 해!","JPN":"それがどうしたというのですか！　空腹だからと仲間を食べるなんて！","ENG":"I don't care! You don't eat your colleague just because you're hungry!","TWN":"和這個有什麼關係啊！因為肚子餓就想把同伴抓來吃，妳是想怎樣啊！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"레지나 님답지 않게 비논리적이시네요. 제가 멈춰야 할 이유를 찾을 수가 없는 걸요.","JPN":"レジーナ様らしくない非論理的思考ですね。我々が食べてはならない理由が見つかりませんが。","ENG":"It's not like you to be so unreasonable, Miss Regina. There is not a single reason we'd have to stop.","TWN":"這不合邏輯，真不像蕾佳娜大人。我們找不到自己必須停下的理由。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그, 그럼......","JPN":"じゃ、じゃあ……","ENG":"W-well, then...","TWN":"那、那麼……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"차, 차기 학회장으로서......!","JPN":"じ、次期学会長として……！","ENG":"A-as the next President of the Society!","TWN":"我、我作為下一任學會長……！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"네......?","JPN":"えっ……？","ENG":"Huh?","TWN":"什麼……?"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"차기 학회장으로서 정식으로 요청하겠어요!","JPN":"次期学会長として正式に要請します！","ENG":"As the next President of the Society, I'd like to make a formal request!","TWN":"我作為下一任學會長正式提出要求！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"리벳을 풀어주세요!!","JPN":"リベットを放してください！！","ENG":"Let Rivet go!","TWN":"請放開里維！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"레지나 님의 뜻을 정말 정말 이해하기 어렵네요.","JPN":"レジーナ様の意図は本当に理解できませんね。","ENG":"It's really hard to know what you have in mind, Miss Regina.","TWN":"要理解蕾佳娜大人的意思真的很困難呢。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"하지만 레지나 님께서 학회를 이어주시겠다면야 기꺼이 말씀대로......","JPN":"ですが、レジーナ様が学会を継いでくださるのならば、喜んでおっしゃるとおりに……","ENG":"But if you're really willing to take over the Society, we'll gladly let—","TWN":"不過，既然蕾佳娜大人願意繼任學會長，那我們很樂意聽從……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아자, 빈틈!","JPN":"よっしゃ、隙あり！","ENG":"Ta! You're off guard!","TWN":"很好，有破綻！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};